    public function permittedAttributesForUpdate(?\Illuminate\Contracts\Auth\Authenticatable $user): array
    {
        if ($this->hasRole($user, 'owner')
            || $this->hasRole($user, 'admin')
            || $this->hasRole($user, 'manager')) {
            return [
                'title',
                'description',
                'status',
                'priority',
                'estimated_hours',
                'due_date',
